const item = $input.first().json;

const title = item.title || '';
const link = item.link || '';
const imageUrl = item.enclosure?.url || item['media:content']?.['@_url'] || '';

// Strip HTML tags from content/summary
const rawSummary = item.contentSnippet || item.summary || item.content || '';
const cleanSummary = rawSummary
  .replace(/<[^>]+>/g, '')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&nbsp;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 500);

const pubDate = item.pubDate || item.isoDate || new Date().toISOString();

return [{
  json: {
    title,
    link,
    imageUrl,
    summary: cleanSummary,
    pubDate,
    slug: title.toLowerCase().replace(/[^a-z0-9]+/g, '-')
  }
}];

const uploadResponse = $input.first().json;
const prevData = $('Code — Extract & Clean Blog Data').first().json;

// Handle various uploadtourl response formats
const hostedUrl = 
  uploadResponse?.url ||
  uploadResponse?.data?.url ||
  uploadResponse?.file?.url ||
  uploadResponse?.link ||
  prevData.imageUrl; // fallback to original if upload fails

return [{
  json: {
    ...prevData,
    hostedImageUrl: hostedUrl
  }
}];

const aiResponse = $input.first().json;
const blogData = $('Code — Merge Hosted URL with Blog Data').first().json;

let captions = { linkedin: '', twitter: '' };

try {
  const raw = aiResponse?.choices?.[0]?.message?.content || '{}';
  // Remove markdown code fences if present
  const cleaned = raw.replace(/```json|```/g, '').trim();
  captions = JSON.parse(cleaned);
} catch (e) {
  // Fallback captions
  captions.linkedin = `📖 New Blog Post: ${blogData.title}\n\n${blogData.summary.substring(0, 200)}...\n\nRead more: ${blogData.link}\n\n#Blog #Business #Content`;
  captions.twitter = `📖 ${blogData.title} — ${blogData.link} #Blog #MustRead`;
}

return [{
  json: {
    ...blogData,
    linkedinCaption: captions.linkedin,
    twitterCaption: captions.twitter
  }
}];

const data = $('Code — Parse AI Captions Safely').first().json;
console.log(`✅ Blog post published: ${data.title}`);
console.log(`🔗 LinkedIn caption length: ${data.linkedinCaption?.length}`);
console.log(`🐦 Twitter caption length: ${data.twitterCaption?.length}`);
console.log(`🖼️ Hosted image: ${data.hostedImageUrl}`);
return [{ json: { status: 'success', title: data.title, timestamp: new Date().toISOString() } }];
